SELECT AVG(credit_score) AS average_credit_score
FROM customer_financial_data
WHERE property_ownership = 1;

SELECT AVG(income) 
FROM customer_financial_data 
WHERE vehicle_ownership = 1 AND credit_score > 700;

SELECT AVG(cfd.income) AS average_monthly_income
FROM customer_financial_data cfd
JOIN credit_accounts ca ON cfd.id = ca.customer_id;

SELECT SUM(income) AS total_income, SUM(expenses) AS total_expenses
FROM customer_financial_data
WHERE codmes = 201801;
